UPDATE TBL_USER_MST
   SET PASS_WD = #{encPassWd}
 WHERE 1=1
   AND HOSP_UUID = #{hospUuid}
   AND USER_ID   = #{userId}
 ORDER BY START_DT DESC
 LIMIT 1

